// idが'myElement'の要素に'class1'というクラスを追加します。
let element = document.getElementById('myElement');
element.classList.add('class1');
// このコードを実行すると、idが'myElement'の要素に'class1'というクラスが追加されます。

// idが'myElement'の要素から'class1'というクラスを削除します。
let element = document.getElementById('myElement');
element.classList.remove('class1');
// このコードを実行すると、idが'myElement'の要素から'class1'というクラスが削除されます。

// idが'myElement'の要素が'class1'というクラスを持っているかどうかを確認します。
let element = document.getElementById('myElement');
console.log(element.classList.contains('class1'));
// このコードを実行すると、コンソールにtrueかfalseが表示されます。

// idが'myElement'の要素の'class1'というクラスをトグルします。
let element = document.getElementById('myElement');
element.classList.toggle('class1');
// このコードを実行すると、idが'myElement'の要素の'class1'クラスが存在すれば削除され、存在しなければ追加されます。

// idが'myElement'の要素が持つ全てのクラスを取得します。
let element = document.getElementById('myElement');
console.log(element.className);
// このコードを実行すると、コンソールにidが'myElement'の要素が持つ全てのクラスが表示されます。

// idが'myElement'の要素が'class1'というクラスを'class2'に置換します。
let element = document.getElementById('myElement');
element.classList.replace('class1', 'class2');
// このコードを実行すると、idが'myElement'の要素の'class1'クラスが'class2'に置換されます。

// idが'myElement'の要素のclassListを取得します。
let element = document.getElementById('myElement');
console.log(element.classList);
// このコードを実行すると、コンソールにidが'myElement'の要素のclassListが表示されます。

// idが'myElement'の要素のクラス名を取得します。
let element = document.getElementById('myElement');
console.log(element.className);
// このコードを実行すると、コンソールにidが'myElement'の要素のクラス名が表示されます。

// idが'myElement'の要素が持つクラスの数を取得します。
let element = document.getElementById('myElement');
console.log(element.classList.length);
// このコードを実行すると、コンソールにidが'myElement'の要素が持つクラスの数が表示されます。

// 'class1'というクラスを持つ要素を全て取得します。
let elements = document.getElementsByClassName('class1');
console.log(elements);
// このコードを実行すると、コンソールに'class1'というクラスを持つ要素が全て表示されます。
